import 'dart:convert';

import '../lib/text_chunker.dart';

void expectEqual(Object? actual, Object? expected) {
  if (actual != expected) {
    throw StateError('Expected $expected, got $actual');
  }
}

void main() {
  const original = 'A\u{1F642}B';
  final chunks = chunkText(original, 2);
  final joinedBytes = <int>[];
  for (final chunk in chunks) {
    utf8.decode(chunk);
    joinedBytes.addAll(chunk);
  }
  expectEqual(utf8.decode(joinedBytes), original);
}
